<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Maze Bots — 24 Autonomous Pathfinders</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #0a0e17;
    color: #c8d6e5;
    font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    min-height: 100vh;
    overflow-x: hidden;
  }
  #hud {
    display: flex;
    align-items: center;
    gap: 28px;
    padding: 14px 32px;
    background: linear-gradient(135deg, #111827, #1a2332);
    border-bottom: 1px solid #1e2d3d;
    width: 100%;
    justify-content: center;
    flex-wrap: wrap;
  }
  #hud span {
    font-size: 15px;
    letter-spacing: 0.5px;
    white-space: nowrap;
  }
  #completed { color: #4ade80; font-weight: 600; min-width: 200px; text-align: center; }
  #timer   { color: #67e8f9; font-weight: 600; min-width: 120px; text-align: center; }
  #reset {
    background: linear-gradient(135deg, #6366f1, #8b5cf6);
    color: #fff;
    border: none;
    padding: 8px 24px;
    border-radius: 8px;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    transition: transform 0.1s, box-shadow 0.2s;
    letter-spacing: 0.5px;
  }
  #reset:hover { transform: translateY(-1px); box-shadow: 0 4px 20px rgba(99,102,241,0.4); }
  #reset:active { transform: translateY(0); }
  #maze-container {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 16px;
    flex: 1;
  }
  canvas#maze {
    border-radius: 8px;
    box-shadow: 0 0 40px rgba(99,102,241,0.15), 0 0 80px rgba(139,92,246,0.08);
  }
</style>
</head>
<body>

<div id="hud">
  <span id="completed">0 / 24 completed</span>
  <span id="timer">0.0s</span>
  <button id="reset">Reset</button>
</div>
<div id="maze-container">
  <canvas id="maze"></canvas>
</div>

<script>
(function() {
  "use strict";

  // ── Constants ──────────────────────────────────────────────
  const ROWS = 15;
  const COLS = 15;
  const NUM_BOTS = 24;
  const SPAWN_R = 0, SPAWN_C = 0;
  const EXIT_R = ROWS - 1, EXIT_C = COLS - 1;

  // Bot colors (vibrant palette)
  const BOT_COLORS = [
    "#f87171","#fb923c","#fbbf24","#a3e635","#34d399",
    "#22d3ee","#60a5fa","#818cf8","#a78bfa","#e879f9",
    "#f472b6","#c084fc","#4ade80","#38bdf8","#facc15",
    "#fb7185","#38bdf8","#a3e635","#fbbf24","#818cf8",
    "#22d3ee","#e879f9","#60a5fa","#f97316"
  ];

  // ── State ──────────────────────────────────────────────────
  let walls = [];          // walls[r][c] = {top,right,bottom,left}
  let distMap = [];        // BFS distance from exit
  let bots = [];           // array of bot objects
  let completedCount = 0;
  let startTime = 0;       // performance.now() timestamp when game started
  let elapsedMs = 0;       // accumulated real elapsed time
  let gameRunning = false;
  let animFrameId = null;

  // ── Maze Generation (Recursive Backtracker) ───────────────
  function generateMaze() {
    walls = [];
    for (let r = 0; r < ROWS; r++) {
      walls[r] = [];
      for (let c = 0; c < COLS; c++) {
        walls[r][c] = { top: true, right: true, bottom: true, left: true };
      }
    }

    const visited = Array.from({ length: ROWS }, () => new Uint8Array(COLS));
    const stack = [];
    let r = SPAWN_R, c = SPAWN_C;
    visited[r][c] = 1;
    stack.push(r * COLS + c);

    while (stack.length > 0) {
      const dirs = [];
      if (r > 0 && !visited[r-1][c]) dirs.push({dr:-1,dc:0,w:"top",ow:"bottom"});
      if (r < ROWS-1 && !visited[r+1][c]) dirs.push({dr:1,dc:0,w:"bottom",ow:"top"});
      if (c > 0 && !visited[r][c-1]) dirs.push({dr:0,dc:-1,w:"left",ow:"right"});
      if (c < COLS-1 && !visited[r][c+1]) dirs.push({dr:0,dc:1,w:"right",ow:"left"});

      if (dirs.length > 0) {
        const pick = dirs[Math.floor(Math.random() * dirs.length)];
        walls[r][c][pick.w] = false;
        walls[r+pick.dr][c+pick.dc][pick.ow] = false;
        visited[r+pick.dr][c+pick.dc] = 1;
        stack.push(r * COLS + c);
        r += pick.dr;
        c += pick.dc;
      } else {
        const prev = stack.pop();
        r = Math.floor(prev / COLS);
        c = prev % COLS;
      }
    }
  }

  // ── BFS from exit ──────────────────────────────────────────
  function computeDistMap() {
    distMap = Array.from({ length: ROWS }, () => new Float64Array(COLS).fill(Infinity));
    const queue = [];
    distMap[EXIT_R][EXIT_C] = 0;
    queue.push(EXIT_R * COLS + EXIT_C);

    while (queue.length > 0) {
      const idx = queue.shift();
      const cr = Math.floor(idx / COLS), cc = idx % COLS;
      const w = walls[cr][cc];
      const d = distMap[cr][cc] + 1;

      if (!w.top && cr > 0 && distMap[cr-1][cc] === Infinity) {
        distMap[cr-1][cc] = d; queue.push((cr-1)*COLS+cc);
      }
      if (!w.bottom && cr < ROWS-1 && distMap[cr+1][cc] === Infinity) {
        distMap[cr+1][cc] = d; queue.push((cr+1)*COLS+cc);
      }
      if (!w.left && cc > 0 && distMap[cr][cc-1] === Infinity) {
        distMap[cr][cc-1] = d; queue.push(cr*COLS+cc-1);
      }
      if (!w.right && cc < COLS-1 && distMap[cr][cc+1] === Infinity) {
        distMap[cr][cc+1] = d; queue.push(cr*COLS+cc+1);
      }
    }
  }

  // ── Path reconstruction: spawn → exit using dist map ─────
  function buildPath(startR, startC) {
    const path = [{r: startR, c: startC}];
    let cr = startR, cc = startC;
    while (cr !== EXIT_R || cc !== EXIT_C) {
      const w = walls[cr][cc];
      let bestD = distMap[cr][cc], br = cr, bc = cc;
      if (!w.top && cr > 0 && distMap[cr-1][cc] < bestD) { bestD = distMap[cr-1][cc]; br=cr-1; bc=cc; }
      if (!w.bottom && cr < ROWS-1 && distMap[cr+1][cc] < bestD) { bestD = distMap[cr+1][cc]; br=cr+1; bc=cc; }
      if (!w.left && cc > 0 && distMap[cr][cc-1] < bestD) { bestD = distMap[cr][cc-1]; br=cr; bc=cc-1; }
      if (!w.right && cc < COLS-1 && distMap[cr][cc+1] < bestD) { bestD = distMap[cr][cc+1]; br=cr; bc=cc+1; }
      path.push({r: br, c: bc});
      cr = br; cc = bc;
    }
    return path;
  }

  // ── Bot creation ───────────────────────────────────────────
  function createBots() {
    const paths = [];
    for (let i = 0; i < NUM_BOTS; i++) {
      paths.push(buildPath(SPAWN_R, SPAWN_C));
    }

    // Shuffle paths so bots don't all follow identical routes
    for (let i = paths.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [paths[i], paths[j]] = [paths[j], paths[i]];
    }

    bots = [];
    for (let i = 0; i < NUM_BOTS; i++) {
      const delay = Math.floor(Math.random() * 25); // stagger 0-24 steps
      bots.push({
        x: SPAWN_C,           // logical cell column
        y: SPAWN_R,           // logical cell row
        vx: SPAWN_C,          // visual column (interpolated)
        vy: SPAWN_R,          // visual row (interpolated)
        path: paths[i],       // precomputed cell sequence
        pathIdx: 0,           // next index in path to move to
        delay: delay,         // steps to wait before moving
        stepCount: 0,         // total steps taken by this bot
        completed: false,
        color: BOT_COLORS[i % BOT_COLORS.length],
        pulsePhase: Math.random() * Math.PI * 2
      });
    }
  }

  // ── Tick (synchronous, deterministic) ─────────────────────
  function tick(n) {
    if (!gameRunning && n > 0) {
      gameRunning = true;
      startTime = performance.now() - elapsedMs;
    }
    for (let step = 0; step < n; step++) {
      let anyMoved = false;
      for (let i = 0; i < NUM_BOTS; i++) {
        const b = bots[i];
        if (b.completed) continue;
        b.stepCount++;
        if (b.stepCount <= b.delay) continue; // still waiting
        if (b.pathIdx >= b.path.length - 1) {
          // reached exit
          b.x = EXIT_C;
          b.y = EXIT_R;
          b.completed = true;
          anyMoved = true;
          continue;
        }
        const next = b.path[b.pathIdx + 1];
        b.x = next.c;
        b.y = next.r;
        b.pathIdx++;
        if (b.pathIdx >= b.path.length - 1) {
          b.completed = true;
        }
        anyMoved = true;
      }
    }
    // Update completed count
    completedCount = bots.filter(b => b.completed).length;
    updateHUD();
  }

  // ── Reset ──────────────────────────────────────────────────
  function reset() {
    if (animFrameId) cancelAnimationFrame(animFrameId);
    animFrameId = null;
    completedCount = 0;
    elapsedMs = 0;
    gameRunning = false;
    startTime = performance.now();
    generateMaze();
    computeDistMap();
    createBots();
    updateHUD();
    draw();
    startAnimation();
  }

  // ── HUD updates ───────────────────────────────────────────
  function updateHUD() {
    document.getElementById("completed").textContent = completedCount + " / " + NUM_BOTS + " completed";
  }

  function updateTimerDisplay() {
    const ms = elapsedMs;
    const s = (ms / 1000).toFixed(1);
    document.getElementById("timer").textContent = s + "s";
  }

  // ── Canvas sizing & drawing ───────────────────────────────
  const canvas = document.getElementById("maze");
  const ctx = canvas.getContext("2d");
  let cellSize = 0;
  let offsetX = 0, offsetY = 0;

  function resizeCanvas() {
    const container = document.getElementById("maze-container");
    const maxW = Math.min(container.clientWidth - 32, 700);
    const maxH = Math.min(container.clientHeight - 32, 700);
    cellSize = Math.floor(Math.min(maxW / COLS, maxH / ROWS));
    canvas.width = cellSize * COLS;
    canvas.height = cellSize * ROWS;
    offsetX = (container.clientWidth - canvas.width) / 2;
    offsetY = (container.clientHeight - canvas.height) / 2;
    draw();
  }

  function cellCenter(r, c) {
    return { x: c * cellSize + cellSize / 2, y: r * cellSize + cellSize / 2 };
  }

  function draw() {
    const W = canvas.width, H = canvas.height;
    // Background
    ctx.fillStyle = "#0f1729";
    ctx.fillRect(0, 0, W, H);

    // Draw floor cells (subtle grid)
    for (let r = 0; r < ROWS; r++) {
      for (let c = 0; c < COLS; c++) {
        const x = c * cellSize, y = r * cellSize;
        ctx.fillStyle = "#131d2e";
        ctx.fillRect(x + 1, y + 1, cellSize - 2, cellSize - 2);
      }
    }

    // Spawn marker
    const sp = cellCenter(SPAWN_R, SPAWN_C);
    const gradS = ctx.createRadialGradient(sp.x, sp.y, 0, sp.x, sp.y, cellSize * 0.7);
    gradS.addColorStop(0, "rgba(74,222,128,0.35)");
    gradS.addColorStop(1, "rgba(74,222,128,0)");
    ctx.fillStyle = gradS;
    ctx.fillRect(SPAWN_C * cellSize, SPAWN_R * cellSize, cellSize, cellSize);

    // Exit marker
    const ep = cellCenter(EXIT_R, EXIT_C);
    const gradE = ctx.createRadialGradient(ep.x, ep.y, 0, ep.x, ep.y, cellSize * 0.7);
    gradE.addColorStop(0, "rgba(251,146,60,0.35)");
    gradE.addColorStop(1, "rgba(251,146,60,0)");
    ctx.fillStyle = gradE;
    ctx.fillRect(EXIT_C * cellSize, EXIT_R * cellSize, cellSize, cellSize);

    // Exit label
    ctx.fillStyle = "#fb923c";
    ctx.font = "bold " + Math.max(10, cellSize * 0.35) + "px system-ui";
    ctx.textAlign = "center";
    ctx.textBaseline = "middle";
    ctx.fillText("EXIT", ep.x, ep.y);

    // Spawn label
    ctx.fillStyle = "#4ade80";
    ctx.font = "bold " + Math.max(9, cellSize * 0.3) + "px system-ui";
    ctx.fillText("SPAWN", sp.x, sp.y);

    // Draw walls
    ctx.strokeStyle = "#2a3f5f";
    ctx.lineWidth = 2.5;
    ctx.lineCap = "round";
    for (let r = 0; r < ROWS; r++) {
      for (let c = 0; c < COLS; c++) {
        const w = walls[r][c];
        const x1 = c * cellSize, y1 = r * cellSize;
        const x2 = (c+1) * cellSize, y2 = (r+1) * cellSize;
        if (w.top)    { ctx.beginPath(); ctx.moveTo(x1,y1); ctx.lineTo(x2,y1); ctx.stroke(); }
        if (w.right)  { ctx.beginPath(); ctx.moveTo(x2,y1); ctx.lineTo(x2,y2); ctx.stroke(); }
        if (w.bottom) { ctx.beginPath(); ctx.moveTo(x1,y2); ctx.lineTo(x2,y2); ctx.stroke(); }
        if (w.left)   { ctx.beginPath(); ctx.moveTo(x1,y1); ctx.lineTo(x1,y2); ctx.stroke(); }
      }
    }

    // Draw bots
    const t = performance.now() / 1000;
    for (let i = 0; i < NUM_BOTS; i++) {
      const b = bots[i];
      if (b.completed) continue;

      // Interpolate visual position toward logical position
      const lerpSpeed = 0.25;
      b.vx += (b.x - b.vx) * lerpSpeed;
      b.vy += (b.y - b.vy) * lerpSpeed;

      const cx = b.vx * cellSize + cellSize / 2;
      const cy = b.vy * cellSize + cellSize / 2;
      const pulse = 0.85 + 0.15 * Math.sin(t * 4 + b.pulsePhase);
      const radius = cellSize * 0.22 * pulse;

      // Glow
      const glow = ctx.createRadialGradient(cx, cy, radius * 0.3, cx, cy, radius * 3);
      glow.addColorStop(0, b.color + "55");
      glow.addColorStop(1, b.color + "00");
      ctx.fillStyle = glow;
      ctx.beginPath();
      ctx.arc(cx, cy, radius * 3, 0, Math.PI * 2);
      ctx.fill();

      // Body
      ctx.fillStyle = b.color;
      ctx.beginPath();
      ctx.arc(cx, cy, radius, 0, Math.PI * 2);
      ctx.fill();

      // Inner highlight
      ctx.fillStyle = "rgba(255,255,255,0.3)";
      ctx.beginPath();
      ctx.arc(cx - radius * 0.2, cy - radius * 0.2, radius * 0.45, 0, Math.PI * 2);
      ctx.fill();
    }

    // Draw completed bots at exit (fading)
    for (let i = 0; i < NUM_BOTS; i++) {
      const b = bots[i];
      if (!b.completed) continue;
      const ep2 = cellCenter(EXIT_R, EXIT_C);
      ctx.fillStyle = b.color + "44";
      ctx.beginPath();
      ctx.arc(ep2.x, ep2.y, cellSize * 0.15, 0, Math.PI * 2);
      ctx.fill();
    }
  }

  // ── Animation loop ────────────────────────────────────────
  function startAnimation() {
    if (animFrameId) return;
    let lastTime = performance.now();

    function frame(now) {
      animFrameId = requestAnimationFrame(frame);
      const dt = now - lastTime;
      lastTime = now;
      elapsedMs += dt;
      updateTimerDisplay();
      draw();
    }
    animFrameId = requestAnimationFrame(frame);
  }

  // ── Public API ────────────────────────────────────────────
  window.game = {
    get bots() {
      return bots.map(b => ({ x: b.x, y: b.y }));
    },
    get completed() {
      return completedCount;
    },
    get elapsedMs() {
      return elapsedMs;
    },
    tick: function(n) {
      tick(n);
    },
    reset: function() {
      reset();
    }
  };

  // ── Init ──────────────────────────────────────────────────
  document.getElementById("reset").addEventListener("click", () => reset());
  window.addEventListener("resize", resizeCanvas);
  reset();
})();
</script>
</body>
</html>
